%%%%%%%%%% Function readlog3.m %%%%%%%%%%% read logfile ver.3% Jerome FAURE% Tuesday, April 9th 2002.% Modified on Thursday, June 22th 2006.%% function [ttl,dat] = readlog3(fNam)% returns the name of the columns and a matrix containing the whole data% of the log file.function [ttl,dat] = readLog3(fNam)  %function headerfid = fopen(fNam);     % file open('name','permission')   lin = fgetl(fid);      % read first line (title)numLin = double(lin); % make char to number (tub = 9)tab = find(numLin==9); % find subscripts = tubtSiz = max(size(tab));% size gives you a dimension, take bigger onettl = cell(tSiz,2); % define a cell ttl{1,1} = 1;ttl{1,2} = lin(1:tab(1)-1);for i=2:tSiz    ttl{i,1} = i;    ttl{i,2}=lin(tab(i-1)+1:tab(i)-1);enddatO = fscanf(fid,'%f',inf);    % original datasizD = max(size(datO));     % size of DatadatO(sizD+1) = datO(1);     % put date on the lastk = find(datO==datO(1));    % find datedatL = k(2:end) - k(1:end-1);% the number of row for each shotnumS = max(size(datL));          % number of shotsdat = zeros(numS,tSiz);  % initializeation of datafor ii=1:numS    dat(ii,1:datL(ii)) = datO(k(ii):k(ii+1)-1);end fclose(fid);
